          // Actually, skip it — the issue says "logged and skipped".
          // We'll just move on; next poll will find the same entry.
          // To avoid infinite loop on a persistently bad entry, sleep and continue.
          await sleep(rateLimitMs);
          continue;
        }

        const isNoise = result.action_type === "noise" ? 1 : 0;

        db.run(
          `INSERT INTO distilled_entries
           (raw_id, incident_id, ts, action_type, summary, is_noise)
           VALUES (?, ?, ?, ?, ?, ?)`,
          [
            row.id,
            row.incident_id,
            row.ts,
            result.action_type,
            result.summary,
            isNoise,
          ]
        );

        // Rate-limit between entries.
        await sleep(rateLimitMs);
      } catch (err) {
        // Log errors and continue — don't let the loop die.
        console.error("Classifier loop error:", err);
        await sleep(pollIntervalMs);
      }
    }
  };

  // Start the loop asynchronously (fire-and-forget).
  loop();

  return {
    stop: () => {
      running = false;
    },
  };
}

